```javascript
const arr = [1, 2];
arr.push(3); // push()로 추가합니다.
console.log(arr.join('')); // join()를 통해 문자열 형태로 출력하면 됩니다.
// output: "1\n" (단순히 공백으로 구분하는 것)
/* 
    만약 ' + '을 사용했다면 다음과 같이 더 깔끔하게 만들었습니다!
*/
let result = [...arr].join('+');
result.forEach((x, i) => { console.log(`${i}: ${x}`); });
```

